+import path from 'node:path';
+
+export interface CommandSpec {
+  cmd: string[];
+  cwd?: string;
+  extraEnv?: Record<string, string>;
+  runtimeEnv?: boolean;
+}
+
+const dotenvCliPath = path.resolve(process.cwd(), 'node_modules/dotenv-cli/cli.js');
+
+const buildRuntimeEnvArgs = (): string[] => {
+  const args: string[] = [];
+
+  if (process.env['CI']) {
+    args.push('-e', '.env.ci');
+  }
+
+  args.push('-e', '.env.runtime', '-e', '.env.local', '-e', '.env');
+
+  return args;
+};
+
+export const fail = (message: string): never => {
+  console.error(message);
+  process.exit(1);
+};
+
+export const runCommand = async (
+  cmd: readonly string[],
+  options: {
+    cwd?: string;
+    extraEnv?: Record<string, string>;
+  } = {},
+): Promise<number> => {
+  const subprocess = Bun.spawn({
+    cmd: [...cmd],
+    cwd: options.cwd,
+    env: options.extraEnv
+      ? { ...process.env, ...options.extraEnv }
+      : process.env,
+    stdin: 'inherit',
+    stdout: 'inherit',
+    stderr: 'inherit',
+  });
+
+  return await subprocess.exited;
+};
+
+export const runWithRuntimeEnvCommand = async (
+  cmd: readonly string[],
+  options: {
+    cwd?: string;
+    extraEnv?: Record<string, string>;
+  } = {},
+): Promise<number> => {
+  const variableArgs = Object.entries(options.extraEnv ?? {}).flatMap(
+    ([key, value]) => ['-v', `${key}=${value}`],
+  );
+
+  return await runCommand(
+    [
+      process.execPath,
+      dotenvCliPath,
+      ...buildRuntimeEnvArgs(),
+      ...variableArgs,
+      '--',
+      ...cmd,
+    ],
+    { cwd: options.cwd },
+  );
+};
+
+export const runCommandsSequentially = async (
+  commands: readonly CommandSpec[],
+): Promise<number> => {
+  for (const command of commands) {
+    const exitCode = command.runtimeEnv
+      ? await runWithRuntimeEnvCommand(command.cmd, {
+          cwd: command.cwd,
+          extraEnv: command.extraEnv,
