import path from 'node:path';

import { fail, runCommandsSequentially } from '../cli/runtime-command';

const playwrightCliPath = path.resolve(process.cwd(), 'node_modules/playwright/cli.js');

const hasProjectFlag = (args: readonly string[]): boolean =>
  args.some((argument) => argument === '--project' || argument.startsWith('--project='));

const collectRequestedProjects = (args: readonly string[]): string[] => {
  const projects: string[] = [];

  for (let index = 0; index < args.length; index += 1) {
    const argument = args[index];

    if (!argument) {
      continue;
    }

    if (argument === '--project') {
      const project = args[index + 1];
      if (project) {
        projects.push(project);
      }
      continue;
    }

    if (argument.startsWith('--project=')) {
      projects.push(argument.slice('--project='.length));
    }
  }

  return projects;
};

const [, , defaultProject, ...rawArguments] = process.argv;

if (!defaultProject) {
  fail(
    'Usage: bun helpers/testing/run-playwright.ts <default-project> [--prewarm-setup] [...playwright-args]',
  );
}

const forwardedArguments: string[] = [];
let prewarmSetup = false;

for (const argument of rawArguments) {
  if (argument === '--prewarm-setup') {
    prewarmSetup = true;
    continue;
  }

  forwardedArguments.push(argument);
}

const playwrightArguments = hasProjectFlag(forwardedArguments)
  ? forwardedArguments
  : [`--project=${defaultProject}`, ...forwardedArguments];

const requestedProjects = collectRequestedProjects(playwrightArguments);
const e2eMode = requestedProjects.some((project) => project.includes('integration'))
  ? 'integration'
  : 'baseline';

const commands = [
  ...(prewarmSetup
    ? [
        {
          cmd: [process.execPath, playwrightCliPath, 'test', '--project=setup'],
          extraEnv: { E2E_MODE: 'baseline' },
          runtimeEnv: true,
        },
      ]
    : []),
  {
    cmd: [process.execPath, playwrightCliPath, 'test', ...playwrightArguments],
    extraEnv: { E2E_MODE: e2eMode },
    runtimeEnv: true,
  },
];

process.exit(await runCommandsSequentially(commands));

