import * as NodeFileSystem from '@effect/platform-node-shared/NodeFileSystem';
import * as FileSystem from '@effect/platform/FileSystem';
import * as PlatformConfigProvider from '@effect/platform/PlatformConfigProvider';
import { ConfigProvider, Effect } from 'effect';
import path from 'node:path';

export interface RuntimeConfigProviderOptions {
  cwd?: string;
}

const EMPTY_PROVIDER = ConfigProvider.fromMap(new Map());

const resolveDotEnvironmentFiles = (
  _options: RuntimeConfigProviderOptions = {},
) => ['.env.dev.local', '.env.dev', '.env'];

const loadDotEnvironmentProvider = (filePath: string) =>
  Effect.gen(function* () {
    const fileSystem = yield* FileSystem.FileSystem;
    const exists = yield* fileSystem.exists(filePath);
    if (!exists) {
      return EMPTY_PROVIDER;
    }

    return yield* PlatformConfigProvider.fromDotEnv(filePath);
  }).pipe(
    Effect.provide(NodeFileSystem.layer),
    Effect.mapError(
      (error) =>
        new Error(`Failed to load config file ${filePath}: ${String(error)}`),
    ),
  );

export const resolveRuntimeConfigFilePaths = (
  options: RuntimeConfigProviderOptions = {},
) => {
  const cwd = options.cwd ?? process.cwd();
  return resolveDotEnvironmentFiles(options).map((file) =>
    path.resolve(cwd, file),
  );
};

export const makeRuntimeConfigProvider = (
  options: RuntimeConfigProviderOptions = {},
) =>
  Effect.gen(function* () {
    let provider = ConfigProvider.fromEnv();

    for (const filePath of resolveRuntimeConfigFilePaths(options)) {
      const dotEnvironmentProvider =
        yield* loadDotEnvironmentProvider(filePath);
      provider = ConfigProvider.orElse(provider, () => dotEnvironmentProvider);
    }

    return provider;
  });

import { afterEach, describe, expect, it } from '@effect/vitest';
import { Effect } from 'effect';
import fs from 'node:fs';
import os from 'node:os';
import path from 'node:path';

import { databaseConfig } from './database-config';
import { makeRuntimeConfigProvider } from './provider';

const readDatabaseUrl = (cwd: string) =>
  makeRuntimeConfigProvider({ cwd }).pipe(
    Effect.flatMap((provider) =>
      databaseConfig.pipe(Effect.withConfigProvider(provider)),
    ),
    Effect.map((config) => config.DATABASE_URL),
  );

describe('provider', () => {
  const originalDatabaseUrl = process.env['DATABASE_URL'];

  afterEach(() => {
    if (originalDatabaseUrl === undefined) {
      delete process.env['DATABASE_URL'];
      return;
    }

    process.env['DATABASE_URL'] = originalDatabaseUrl;
  });

  it.effect(
    'applies config precedence env > .env.dev.local > .env.dev > .env',
    () =>
      Effect.gen(function* () {
        const temporaryDirectory = fs.mkdtempSync(
          path.join(os.tmpdir(), 'evorto-config-provider-'),
        );

        try {
          fs.writeFileSync(
            path.join(temporaryDirectory, '.env'),
            'DATABASE_URL=postgresql://secrets.example/app\n',
          );
          fs.writeFileSync(
            path.join(temporaryDirectory, '.env.dev'),
            'DATABASE_URL=postgresql://worktree.example/app\n',
          );
          fs.writeFileSync(
            path.join(temporaryDirectory, '.env.dev.local'),
            'DATABASE_URL=postgresql://shared.example/app\n',
          );

          delete process.env['DATABASE_URL'];
          expect(yield* readDatabaseUrl(temporaryDirectory)).toBe(
            'postgresql://shared.example/app',
          );

          fs.unlinkSync(path.join(temporaryDirectory, '.env.dev.local'));
          expect(yield* readDatabaseUrl(temporaryDirectory)).toBe(
            'postgresql://worktree.example/app',
          );

          fs.unlinkSync(path.join(temporaryDirectory, '.env.dev'));
          expect(yield* readDatabaseUrl(temporaryDirectory)).toBe(
            'postgresql://secrets.example/app',
          );

          process.env['DATABASE_URL'] = 'postgresql://env.example/app';
          expect(yield* readDatabaseUrl(temporaryDirectory)).toBe(
            'postgresql://env.example/app',
          );
        } finally {
          fs.rmSync(temporaryDirectory, { force: true, recursive: true });
        }
      }),
  );
});

