import { describe, expect, it } from '@effect/vitest';
import { ConfigError, ConfigProvider, Effect } from 'effect';

import { formatConfigError } from './config-error';
import {
  makePlaywrightEnvironmentConfig,
  requiresIntegrationOnlyPlaywrightEnvironment,
} from './test-runtime-config';

const readPlaywrightEnvironment = (
  provider: ConfigProvider.ConfigProvider,
  argv?: readonly string[],
) =>
  makePlaywrightEnvironmentConfig(argv).pipe(
    Effect.withConfigProvider(provider),
    Effect.mapError(
      (error: ConfigError.ConfigError) =>
        new Error(
          `Invalid Playwright e2e configuration:\n${formatConfigError(error)}`,
        ),
    ),
  );

const requiredPlaywrightEntries = [
  ['CLIENT_ID', 'client-id'],
  ['CLIENT_SECRET', 'client-secret'],
  ['DATABASE_URL', 'postgresql://db.example/app'],
  ['ISSUER_BASE_URL', 'https://issuer.example'],
  ['SECRET', 'super-secret'],
  ['STRIPE_API_KEY', 'stripe-api-key'],
  ['STRIPE_TEST_ACCOUNT_ID', 'acct_123'],
  ['STRIPE_WEBHOOK_SECRET', 'whsec_123'],
] as const;

describe('test-runtime-config', () => {
  it('treats UI mode as unrestricted for integration-only credentials', () => {
    expect(
      requiresIntegrationOnlyPlaywrightEnvironment([
        'node',
        'playwright',
        'test',
        '--ui',
      ]),
    ).toBe(false);
  });

  it('treats explicitly selected baseline projects as baseline-only', () => {
    expect(
      requiresIntegrationOnlyPlaywrightEnvironment([
        'node',
        'playwright',
        'test',
        '--project=local-chrome-baseline',
      ]),
    ).toBe(false);
    expect(
      requiresIntegrationOnlyPlaywrightEnvironment([
        'node',
        'playwright',
        'test',
        '--project',
        'docs-baseline',
      ]),
    ).toBe(false);
  });

  it('treats integration project selection as requiring integration credentials', () => {
    expect(
      requiresIntegrationOnlyPlaywrightEnvironment([
        'node',
        'playwright',
        'test',
        '--project=docs-integration',
      ]),
    ).toBe(true);
  });

  it.effect('requires BASE_URL and ignores PLAYWRIGHT_TEST_BASE_URL', () =>
    Effect.gen(function* () {
    const provider = ConfigProvider.fromMap(
      new Map([
        ...requiredPlaywrightEntries,
        ['PLAYWRIGHT_TEST_BASE_URL', 'http://localhost:4200'],
      ]),
    );

    const error = yield* Effect.flip(readPlaywrightEnvironment(provider));
    expect(error.message).toMatch(/BASE_URL/);
    })
  );

  it.effect('accepts BASE_URL as the canonical Playwright app URL', () =>
    Effect.gen(function* () {
      const provider = ConfigProvider.fromMap(
        new Map([
          ...requiredPlaywrightEntries,
          ['BASE_URL', 'http://localhost:4200'],
        ]),
      );
      const environment = yield* readPlaywrightEnvironment(provider);

      expect(environment.NO_WEBSERVER).toBe(false);
      expect(environment.BASE_URL).toBe('http://localhost:4200');
    }),
  );

  it.effect('still resolves BASE_URL when NO_WEBSERVER disables only auto-startup', () =>
    Effect.gen(function* () {
      const provider = ConfigProvider.fromMap(
        new Map([
          ...requiredPlaywrightEntries,
          ['BASE_URL', 'http://localhost:4200'],
          ['NO_WEBSERVER', 'true'],
        ]),
      );
      const environment = yield* readPlaywrightEnvironment(provider);

      expect(environment.NO_WEBSERVER).toBe(true);
      expect(environment.BASE_URL).toBe('http://localhost:4200');
    }),
  );

  it.effect('does not require Auth0 Management or Cloudflare Images in CI when only baseline projects are selected', () =>
    Effect.gen(function* () {
      const provider = ConfigProvider.fromMap(
        new Map([
          ...requiredPlaywrightEntries,
          ['BASE_URL', 'http://localhost:4200'],
          ['CI', 'true'],
          ['S3_ACCESS_KEY_ID', 'access-key'],
          ['S3_BUCKET', 'bucket'],
          ['S3_ENDPOINT', 'http://minio:9000'],
          ['S3_REGION', 'us-east-1'],
          ['S3_SECRET_ACCESS_KEY', 'secret-key'],
        ]),
      );
      const environment = yield* readPlaywrightEnvironment(provider, [
        'node',
        'playwright',
        'test',
        '--project=local-chrome-baseline',
      ]);

      expect(environment.CI).toBe(true);
    }),
  );

  it.effect('requires Auth0 Management and Cloudflare Images in CI when an integration project is selected', () =>
    Effect.gen(function* () {
      const provider = ConfigProvider.fromMap(
        new Map([
          ...requiredPlaywrightEntries,
          ['BASE_URL', 'http://localhost:4200'],
          ['CI', 'true'],
          ['S3_ACCESS_KEY_ID', 'access-key'],
          ['S3_BUCKET', 'bucket'],
          ['S3_ENDPOINT', 'http://minio:9000'],
          ['S3_REGION', 'us-east-1'],
          ['S3_SECRET_ACCESS_KEY', 'secret-key'],
        ]),
      );

      const error = yield* Effect.flip(
        readPlaywrightEnvironment(provider, [
          'node',
          'playwright',
          'test',
          '--project=docs-integration',
        ]),
      );
      expect(error.message).toMatch(
        /AUTH0_MANAGEMENT_CLIENT_ID[\s\S]*CLOUDFLARE_ACCOUNT_ID|CLOUDFLARE_ACCOUNT_ID[\s\S]*AUTH0_MANAGEMENT_CLIENT_ID/,
      );
    }),
  );
});

import { Config, ConfigError, Effect, Option } from 'effect';
import path from 'node:path';

import { nonEmptyTrimmedString, optionalTrimmedString } from './config-string';

const DEFAULT_TEST_CLOCK_ISO = '2026-02-01T12:00:00.000Z';
const DEFAULT_TEST_SEED_KEY = 'evorto-e2e-default-v1';
const INTEGRATION_PROJECT_NAMES = ['docs-integration'] as const;

export const testRuntimeConfigState = Config.all({
  AUTH0_MANAGEMENT_CLIENT_ID: optionalTrimmedString(
    'AUTH0_MANAGEMENT_CLIENT_ID',
  ),
  AUTH0_MANAGEMENT_CLIENT_SECRET: optionalTrimmedString(
    'AUTH0_MANAGEMENT_CLIENT_SECRET',
  ),
  BASE_URL: optionalTrimmedString('BASE_URL'),
  CI: Config.boolean('CI').pipe(Config.withDefault(false)),
  CLIENT_ID: optionalTrimmedString('CLIENT_ID'),
  CLIENT_SECRET: optionalTrimmedString('CLIENT_SECRET'),
  CLOUDFLARE_ACCOUNT_ID: optionalTrimmedString('CLOUDFLARE_ACCOUNT_ID'),
  CLOUDFLARE_IMAGES_API_TOKEN: optionalTrimmedString(
    'CLOUDFLARE_IMAGES_API_TOKEN',
  ),
  CLOUDFLARE_IMAGES_DELIVERY_HASH: optionalTrimmedString(
    'CLOUDFLARE_IMAGES_DELIVERY_HASH',
  ),
  DATABASE_URL: nonEmptyTrimmedString('DATABASE_URL'),
  DOCS_IMG_OUT_DIR: optionalTrimmedString('DOCS_IMG_OUT_DIR').pipe(
    Config.map((value) =>
      Option.match(value, {
        onNone: () => path.resolve('test-results/docs/images'),
        onSome: (outputDirectory) => outputDirectory,
      }),
    ),
  ),
  DOCS_OUT_DIR: optionalTrimmedString('DOCS_OUT_DIR').pipe(
    Config.map((value) =>
      Option.match(value, {
        onNone: () => path.resolve('test-results/docs'),
        onSome: (outputDirectory) => outputDirectory,
      }),
    ),
  ),
  E2E_NOW_ISO: optionalTrimmedString('E2E_NOW_ISO').pipe(
    Config.map((value) =>
      Option.match(value, {
        onNone: () => DEFAULT_TEST_CLOCK_ISO,
        onSome: (nowIso) => nowIso,
      }),
    ),
  ),
  E2E_SEED_KEY: optionalTrimmedString('E2E_SEED_KEY').pipe(
    Config.map((value) =>
      Option.match(value, {
        onNone: () => DEFAULT_TEST_SEED_KEY,
        onSome: (seedKey) => seedKey,
      }),
    ),
  ),
  ISSUER_BASE_URL: optionalTrimmedString('ISSUER_BASE_URL'),
  NEON_LOCAL_PROXY: Config.boolean('NEON_LOCAL_PROXY').pipe(
    Config.withDefault(false),
  ),
  NO_WEBSERVER: Config.boolean('NO_WEBSERVER').pipe(Config.withDefault(false)),
  S3_ACCESS_KEY_ID: optionalTrimmedString('S3_ACCESS_KEY_ID'),
  S3_BUCKET: optionalTrimmedString('S3_BUCKET'),
  S3_ENDPOINT: optionalTrimmedString('S3_ENDPOINT'),
  S3_REGION: optionalTrimmedString('S3_REGION'),
  S3_SECRET_ACCESS_KEY: optionalTrimmedString('S3_SECRET_ACCESS_KEY'),
  SECRET: optionalTrimmedString('SECRET'),
  STRIPE_API_KEY: optionalTrimmedString('STRIPE_API_KEY'),
  STRIPE_TEST_ACCOUNT_ID: optionalTrimmedString('STRIPE_TEST_ACCOUNT_ID'),
  STRIPE_WEBHOOK_SECRET: optionalTrimmedString('STRIPE_WEBHOOK_SECRET'),
  TENANT_DOMAIN: optionalTrimmedString('TENANT_DOMAIN'),
});

export interface Auth0ManagementEnvironment {
  AUTH0_MANAGEMENT_CLIENT_ID: string;
  AUTH0_MANAGEMENT_CLIENT_SECRET: string;
}

export interface DocumentationOutputEnvironment {
  docsImageOutputDirectory: string;
  docsOutputDirectory: string;
}

export type PlaywrightEnvironment = Omit<
  TestRuntimeConfigState,
  | 'BASE_URL'
  | 'CLIENT_ID'
  | 'CLIENT_SECRET'
  | 'ISSUER_BASE_URL'
  | 'SECRET'
  | 'STRIPE_API_KEY'
  | 'STRIPE_TEST_ACCOUNT_ID'
  | 'STRIPE_WEBHOOK_SECRET'
> & {
  BASE_URL: string;
  CLIENT_ID: string;
  CLIENT_SECRET: string;
  ISSUER_BASE_URL: string;
  NO_WEBSERVER: boolean;
  SECRET: string;
  STRIPE_API_KEY: string;
  STRIPE_TEST_ACCOUNT_ID: string;
  STRIPE_WEBHOOK_SECRET: string;
};

export type TestRuntimeConfigState = Config.Config.Success<
  typeof testRuntimeConfigState
>;

const combineMissingDataErrors = (
  errors: readonly ConfigError.ConfigError[],
) => {
  const [firstError, ...restErrors] = errors;
  if (!firstError) {
    throw new Error('Expected at least one config error');
  }

  let combinedError = firstError;
  for (const error of restErrors) {
    combinedError = ConfigError.And(combinedError, error);
  }

  return combinedError;
};

const missingFieldError = (name: string) =>
  ConfigError.MissingData([name], `Expected ${name} to be configured`);

const collectMissingFieldErrors = (
  fields: readonly [name: string, configured: boolean][],
) =>
  fields
    .map(([name, configured]) =>
      configured ? undefined : missingFieldError(name),
    )
    .filter((value): value is ConfigError.ConfigError => value !== undefined);

const matchesProjectPattern = (pattern: string, projectName: string) => {
  const escapedPattern = pattern.replaceAll(/[|\\{}()[\]^$+?.]/g, '\\$&');
  const projectPattern = new RegExp(
    `^${escapedPattern.replaceAll('*', '.*')}$`,
    'u',
  );
  return projectPattern.test(projectName);
};

const resolveRequestedProjectNames = (argv: readonly string[]) => {
  const requestedProjectNames: string[] = [];

  for (let index = 0; index < argv.length; index += 1) {
    const argument = argv[index];
    if (!argument) {
      continue;
    }

    if (argument === '--project') {
      const nextArgument = argv[index + 1];
      if (!nextArgument) {
        continue;
      }

      requestedProjectNames.push(
        ...nextArgument.split(',').map((projectName) => projectName.trim()),
      );
      index += 1;
      continue;
    }

    if (argument.startsWith('--project=')) {
      requestedProjectNames.push(
        ...argument
          .slice('--project='.length)
          .split(',')
          .map((projectName) => projectName.trim()),
      );
    }
  }

  return requestedProjectNames.filter((projectName) => projectName.length > 0);
};

export const requiresIntegrationOnlyPlaywrightEnvironment = (
  argv: readonly string[] = process.argv,
) => {
  if (argv.includes('--ui')) {
    return false;
  }

  const requestedProjectNames = resolveRequestedProjectNames(argv);
  if (requestedProjectNames.length === 0) {
    return true;
  }

  return requestedProjectNames.some((requestedProjectName) =>
    INTEGRATION_PROJECT_NAMES.some((integrationProjectName) =>
      matchesProjectPattern(requestedProjectName, integrationProjectName),
    ),
  );
};

const validateCiEnvironment = (
  state: TestRuntimeConfigState,
  argv: readonly string[] = process.argv,
) => {
  if (!state.CI) {
    return Effect.void;
  }

  const requiresIntegrationEnvironment =
    requiresIntegrationOnlyPlaywrightEnvironment(argv);
